  ('customs-7fec267e-moex-00010', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '2001年9月11日美國紐約發生恐怖攻擊事件，導致雙子星大樓與鄰近數棟辦公大樓倒塌，其後也使 得不少公司紛紛將辦公室遷往鄰近郊區寬廣之處，不再以高樓為辦公室首選。以上事件對於紐約市 中心區的辦公室租賃市場會產生何種影響？', '["供給曲線不動，需求曲線向左平移，均衡租金下降，成交量減少", "供給曲線向左平移，需求曲線不動，均衡租金上升，成交量減少", "供給曲線向左平移，需求曲線向左平移，均衡租金變動方向不確定，成交量增加", "供給曲線向左平移，需求曲線向左平移，均衡租金變動方向不確定，成交量減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00011', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '若某一消費者之效用函數為U(X,Y)=aX+bY（其中a>0，b>0），則下列何者不適用此一效用函數所對 應之無異曲線？', '["凸向原點", "斜率為負", "不相交", "位置愈高，滿足水準愈高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00012', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '若一消費者之效用函數為U=U(x,y)，擁有所得M，其在面對兩產品價格Px與Py下，選擇了效用極 大化的唯一最適消費財貨組合(x*,y*)。下列何者變動將會改變消費者的最適選擇？', '["效用函數變為U(x,y)+100", "所得變為M+100", "價格與所得均變為2倍", "效用函數變為2U(x,y)"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00013', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '對某甲而言，X和Y為完全互補品，甲的預算限制式為PX+P Y=I，其中I為所得，則： x Y', '["X和Y的所得彈性為1", "X和Y當中，可能一個為正常品，而另一個為劣等品", "X和Y的所得彈性皆為0.5", "資訊不足以判斷X和Y的所得彈性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00014', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', 'X的需求曲線是負斜率的。當X的價格為2元時，需求量為200。當X的價格上漲為3元時，消費 者剩餘如何變動？', '["會減少，減少金額不超過200元", "會減少，減少金額超過200元", "會增加，增加金額不超過200元", "會增加，增加金額超過200元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00015', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '隨著某種生產要素使用量增加，使用這種生產要素替代另一種要素的效果愈來愈差，這表示邊際技 術替代率（MRTS）具有何種的特性？', '["不變", "遞增", "遞減", "遞增遞減皆有可能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
